const questionsData = $node["Recuperer Toutes les Questions"].json;
const allQuestions = Array.isArray(questionsData) ? questionsData : (questionsData.questions || []);

const webhookRaw = $node["Quiz Webhook"].json || {};
const body = webhookRaw.body && typeof webhookRaw.body === 'object' ? webhookRaw.body : webhookRaw;
const answersSoFar = Array.isArray(body.answersSoFar) ? body.answersSoFar : [];
const sessionId = String(body.sessionId || `session-${body.userId || 0}`);

const hashString = (str) => {
  let h = 2166136261;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 16777619);
  }
  return h >>> 0;
};

const mulberry32 = (a) => () => {
  let t = (a += 0x6D2B79F5);
  t = Math.imul(t ^ (t >>> 15), t | 1);
  t ^= t + Math.imul(t ^ (t >>> 7), t | 61);
  return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
};

const shuffle = (arr, rng) => {
  const out = [...arr];
  for (let i = out.length - 1; i > 0; i--) {
    const j = Math.floor(rng() * (i + 1));
    [out[i], out[j]] = [out[j], out[i]];
  }
  return out;
};

const rng = mulberry32(hashString(sessionId));

const byQuiz = allQuestions.reduce((acc, q) => {
  const quizId = String(q.quizId ?? q.quiz_id ?? 'unknown');
  if (!acc[quizId]) acc[quizId] = [];
  acc[quizId].push(q);
  return acc;
}, {});

Object.keys(byQuiz).forEach((key) => {
  const sorted = [...byQuiz[key]].sort((a, b) => Number(a.id) - Number(b.id));
  byQuiz[key] = shuffle(sorted, rng);
});

const quizIds = shuffle(Object.keys(byQuiz).sort((a, b) => Number(a) - Number(b)), rng);
const mixedQuestions = [];
let keepGoing = true;
let offset = 0;

while (keepGoing) {
  keepGoing = false;
  for (const qid of quizIds) {
    const list = byQuiz[qid];
    if (offset < list.length) {
      mixedQuestions.push(list[offset]);
      keepGoing = true;
    }
  }
  offset += 1;
}

const quizQuestions = mixedQuestions;
const maxQuestions = Number(body.maxQuestions || Math.min(12, quizQuestions.length || 10));

if (quizQuestions.length === 0) {
  return { status: "complete", analysis: "No questions were found in the database.", score: 0, answersJSON: JSON.stringify(answersSoFar), questionsJSON: JSON.stringify([]), sessionId };
}

const answeredIds = answersSoFar.map((a) => Number(a.questionId)).filter((id) => !Number.isNaN(id));
const remainingQuestions = quizQuestions.filter((q) => !answeredIds.includes(Number(q.id)));

if (answersSoFar.length === 0) {
  return {
    status: "continue",
    mode: "opening",
    nextQuestion: quizQuestions[0],
    answersJSON: JSON.stringify([]),
    questionsJSON: JSON.stringify(quizQuestions),
    remainingQuestionsJSON: JSON.stringify(quizQuestions.slice(1)),
    sessionId
  };
}

if (remainingQuestions.length === 0 || answersSoFar.length >= maxQuestions) {
  return {
    status: "complete",
    answersJSON: JSON.stringify(answersSoFar),
    questionsJSON: JSON.stringify(quizQuestions),
    sessionId
  };
}

return {
  status: "continue",
  mode: "adaptive",
  answersJSON: JSON.stringify(answersSoFar),
  questionsJSON: JSON.stringify(quizQuestions),
  remainingQuestionsJSON: JSON.stringify(remainingQuestions),
  sessionId
};

const base = $node["Determiner Prochaine Etape"].json;

if (base.mode === 'opening' && base.nextQuestion) {
  return { status: 'continue', nextQuestion: base.nextQuestion };
}

const answers = JSON.parse(base.answersJSON || '[]');
const remainingQuestions = JSON.parse(base.remainingQuestionsJSON || '[]');

if (!remainingQuestions.length) {
  return { status: 'complete', score: 82 };
}

const allAnswerText = answers.map((a) => String(a.answer || '')).join(' ').toLowerCase();
const lastAnswer = String(answers[answers.length - 1]?.answer || '').toLowerCase();

const tokenize = (txt) => String(txt || '').toLowerCase().replace(/[^a-z0-9_\s]/g, ' ').split(/\s+/).filter((t) => t.length > 2);
const answerTokens = new Set(tokenize(`${lastAnswer} ${allAnswerText}`));

const questionScore = (q) => {
  const optionText = Array.isArray(q.options) ? q.options.map((o) => o?.text || o).join(' ') : '';
  const qTokens = tokenize(`${q.text || ''} ${optionText}`);
  let overlap = 0;
  for (const t of qTokens) {
    if (answerTokens.has(t)) overlap += 1;
  }
  const typeBonus = String(q.type || '').toLowerCase().includes('multiple') ? 0.5 : 0;
  const diversityBonus = (q.quizId || q.quiz_id) ? 0.2 : 0;
  return overlap + typeBonus + diversityBonus;
};

const ranked = [...remainingQuestions].sort((a, b) => questionScore(b) - questionScore(a) || Number(a.id) - Number(b.id));

const categories = [
  /(oily|dry|combination|normal|sensitive|skin type|tight|shiny|flaky)/i,
  /(acne|pores|redness|pigmentation|aging|dehydration|dullness|blackheads)/i,
  /(sunscreen|sun exposure|uv|spf)/i,
  /(sleep|stress|diet|water|climate|pollution|smoke)/i,
  /(cleanser|exfoliate|routine|moisturizer|product|texture)/i
];

let covered = 0;
for (const re of categories) {
  if (re.test(allAnswerText)) covered += 1;
}

const informativeAnswers = answers.filter((a) => {
  const txt = String(a.answer || '').trim().toLowerCase();
  return txt.length > 2 && !['idk', 'unknown', 'none', 'n/a', 'not sure'].includes(txt);
}).length;

const informativeRatio = answers.length ? informativeAnswers / answers.length : 0;
const requiredQuestions = 10;
const shouldStop = answers.length >= requiredQuestions;

if (shouldStop) {
  return {
    status: 'complete',
    score: Math.min(95, 68 + covered * 5 + Math.round(informativeRatio * 10))
  };
}

return { status: 'continue', nextQuestion: ranked[0] || remainingQuestions[0] };

const src = $node["Decision Adaptative Locale"].json || {};
if (src.nextQuestion) {
  return { status: 'continue', nextQuestion: src.nextQuestion };
}
return { status: 'complete', analysis: 'Questionnaire complete: no next question.', score: Number(src.score || 80) };

