const src = $node["Gemini Analyse Finale"].json || {};

let parsed = null;
try {
  const raw = src?.choices?.[0]?.message?.content || '{}';
  const txt = typeof raw === 'string' ? raw : JSON.stringify(raw);
  parsed = JSON.parse(txt);
} catch (e) {
  parsed = null;
}

return {
  status: 'complete',
  analysis: String(parsed?.analysis || src?.error?.message || 'Analysis complete.'),
  score: Number(parsed?.score || 80)
};
